    int state[] = {1, 2, 3, 4, 5};
    fwrite(state, sizeof(int), 5, fp);
    fclose(fp);
    printf("State saved");
    return 0;
}

#include <stdio.h>
int main() {
    FILE *fp = fopen("transactions.log", "a");
    fprintf(fp, "BEGIN\n");
    fprintf(fp, "INSERT 42\n");
    fprintf(fp, "COMMIT\n");
    fflush(fp);
    fclose(fp);
    printf("Transaction logged");
    return 0;
}

#include <stdio.h>
int main() {
    FILE *fp = fopen("bitmap.bmp", "wb");
    unsigned char header[54] = {0x42, 0x4D};
    fwrite(header, 1, 54, fp);
    fclose(fp);
    printf("BMP header written");
    return 0;
}

#include <stdio.h>
int main() {
    FILE *fp = fopen("endian.bin", "wb");
    unsigned int x = 0x01020304;
    fwrite(&x, sizeof(unsigned int), 1, fp);
    fclose(fp);
    printf("Written");
    return 0;
}

